SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(bs.weight) AS units_count, min(bs."out.electricity.total.energy_consumption" * 1) AS "electricity.total.energy_consumption__min" FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.applicability = true AND bs.upgrade = 0 AND bs."in.state" = 'CO' GROUP BY 1 ORDER BY 1